/**
 * A fully parsed MAVLink message with decoded payload
 */
interface ParsedMAVLinkMessage {
    timestamp: number;
    system_id: number;
    component_id: number;
    message_id: number;
    message_name: string;
    sequence: number;
    payload: Record<string, unknown>;
    protocol_version: 1 | 2;
    checksum: number;
    crc_ok: boolean;
    signature?: Uint8Array;
    dialect?: string;
}
/**
 * A raw MAVLink frame before payload decoding
 */
interface MAVLinkFrame {
    magic: number;
    length: number;
    incompatible_flags?: number;
    compatible_flags?: number;
    sequence: number;
    system_id: number;
    component_id: number;
    message_id: number;
    payload: Uint8Array;
    checksum: number;
    signature?: Uint8Array;
    crc_ok?: boolean;
    protocol_version?: 1 | 2;
}
/**
 * Definition of a single field within a message
 */
interface FieldDefinition {
    name: string;
    type: string;
    arrayLength?: number;
    extension?: boolean;
}
/**
 * Definition of a complete MAVLink message
 */
interface MessageDefinition {
    id: number;
    name: string;
    fields: FieldDefinition[];
}
/**
 * Interface for message parsing functionality
 */
interface IMessageParser {
    parseBytes(data: Uint8Array): ParsedMAVLinkMessage[];
    decode(frame: MAVLinkFrame): ParsedMAVLinkMessage;
    resetBuffer(): void;
}
/**
 * Interface for message serialization functionality
 */
interface IMessageSerializer {
    serializeMessage(message: Record<string, unknown> & {
        message_name: string;
    }): Uint8Array;
    completeMessage(message: Record<string, unknown> & {
        message_name: string;
    }): Record<string, unknown>;
}
/**
 * Interface for message registry functionality
 */
interface IMessageRegistry {
    getMessageDefinition(id: number): MessageDefinition | undefined;
    getMessageDefinitionByName(name: string): MessageDefinition | undefined;
    supportsMessage(messageId: number): boolean;
    supportsMessageName(messageName: string): boolean;
    getSupportedMessageIds(): number[];
    getSupportedMessageNames(): string[];
}

export type { FieldDefinition, IMessageParser, IMessageRegistry, IMessageSerializer, MAVLinkFrame, MessageDefinition, ParsedMAVLinkMessage };
